DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `transactions` (
  `id` int(30) NOT NULL AUTO_INCREMENT,
  `reference_code` varchar(100) DEFAULT NULL,
  `type` varchar(50) NOT NULL COMMENT 'sale, purchase, expense, payment, return, adjustment, opening_balance, opening_stock',
  `entity_type` varchar(50) DEFAULT NULL,
  `entity_id` int(30) DEFAULT NULL COMMENT 'FK to entity_list (customer or supplier)',
  `account_id` int(30) DEFAULT NULL COMMENT 'FK to account_list (payment account)',
  `parent_id` int(30) DEFAULT NULL COMMENT 'For payments and returns, references parent transaction',
  `total_amount` float NOT NULL DEFAULT 0,
  `discount_perc` float NOT NULL DEFAULT 0,
  `discount` float NOT NULL DEFAULT 0,
  `tax_perc` float NOT NULL DEFAULT 0,
  `tax` float NOT NULL DEFAULT 0,
  `payment_terms` varchar(50) DEFAULT 'Cash',
  `remarks` text DEFAULT NULL,
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '0=Pending,1=Active/Paid',
  `transaction_date` date DEFAULT NULL,
  `created_by` int(30) DEFAULT NULL COMMENT 'FK to users.id',
  `updated_by` int(30) DEFAULT NULL,
  `date_created` datetime NOT NULL DEFAULT current_timestamp(),
  `date_updated` datetime DEFAULT NULL ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `entity_id` (`entity_id`),
  KEY `account_id` (`account_id`),
  KEY `parent_id` (`parent_id`),
  KEY `type` (`type`),
  KEY `transaction_date` (`transaction_date`),
  KEY `reference_code` (`reference_code`),
  KEY `status` (`status`),
  KEY `created_by` (`created_by`),
  KEY `reference_code_2` (`reference_code`)
) ENGINE=InnoDB AUTO_INCREMENT=154 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

